module signal_generator(
    input clk,
    input rst_n,
    output [4:0] wave
);

    reg [4:0] wave_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wave_reg <= 5'b00000;
        end
        else begin
            if (wave_reg == 5'b11111) begin
                wave_reg <= wave_reg - 1;
            end
            else begin
                wave_reg <= wave_reg + 1;
            end
        end
    end

    assign wave = wave_reg;

endmodule
